function collectRengeLocalStorage() {
  const entries: Record<string, string> = {};
  for (let index = 0; index < localStorage.length; index += 1) {
    const key = localStorage.key(index);
    if (!key?.startsWith(RENGE_STORAGE_PREFIX)) continue;
    entries[key] = localStorage.getItem(key) ?? "";
  }
  return entries;
}

function replaceRengeLocalStorage(entries: Record<string, string>) {
  const currentKeys = Array.from({ length: localStorage.length }, (_, index) =>
    localStorage.key(index),
  ).filter((key): key is string => Boolean(key?.startsWith(RENGE_STORAGE_PREFIX)));
  currentKeys.forEach((key) => localStorage.removeItem(key));
  Object.entries(entries).forEach(([key, value]) => {
    if (key.startsWith(RENGE_STORAGE_PREFIX)) localStorage.setItem(key, value);
  });
}

function parseCompleteBackup(value: unknown): RengeCompleteBackup {
  if (!isObjectRecord(value)) throw new Error("еӨҮд»Ҫж–Үд»¶дёҚжҳҜжңүж•Ҳзҡ„ JSON еҜ№иұЎгҖӮ");
  if (value.format !== COMPLETE_BACKUP_FORMAT) {
    throw new Error("иҝҷдёҚжҳҜ Renge Agent е®Ңж•ҙеӨҮд»Ҫж–Үд»¶гҖӮ");
  }
  if (value.version !== COMPLETE_BACKUP_VERSION) {
    throw new Error(`жҡӮдёҚж”ҜжҢҒжӯӨеӨҮд»ҪзүҲжң¬пјҡ${String(value.version ?? "жңӘзҹҘ")}гҖӮ`);
  }
  if (typeof value.exportedAt !== "string" || !isObjectRecord(value.appData)) {
    throw new Error("еӨҮд»Ҫзјәе°‘еҜјеҮәж—¶й—ҙжҲ–еә”з”Ёдё»ж•°жҚ®гҖӮ");
  }
  if (!isObjectRecord(value.localStorage)) {
    throw new Error("еӨҮд»Ҫзјәе°‘жң¬ең°и®ҫзҪ®ж•°жҚ®гҖӮ");
  }

  const requiredArrayFields: Array<keyof RengeAppData> = [
    "personas",
    "providers",
    "chatSessions",
    "systemPrompts",
    "chatPresets",
    "worldBooks",
    "regexScripts",
    "tavernScripts",
    "characterCards",
    "mcpServers",
    "skills",
    "extensions",
  ];
  for (const field of requiredArrayFields) {
    if (!Array.isArray(value.appData[field])) {
      throw new Error(`еӨҮд»Ҫзјәе°‘е®Ңж•ҙж•°жҚ®еӯ—ж®өпјҡ${field}гҖӮ`);
    }
  }

  const storageEntries: Record<string, string> = {};
  for (const [key, entryValue] of Object.entries(value.localStorage)) {
    if (!key.startsWith(RENGE_STORAGE_PREFIX) || typeof entryValue !== "string") {
      throw new Error("еӨҮд»Ҫдёӯзҡ„жң¬ең°и®ҫзҪ®ж јејҸж— ж•ҲгҖӮ");
    }
    storageEntries[key] = entryValue;
  }
  if (
    value.desktopProjectPositions !== undefined &&
    value.desktopProjectPositions !== null &&
    !isObjectRecord(value.desktopProjectPositions)
  ) {
    throw new Error("еӨҮд»Ҫдёӯзҡ„жЎҢйқўеӣҫж ҮдҪҚзҪ®ж јејҸж— ж•ҲгҖӮ");
  }

  return {
    format: COMPLETE_BACKUP_FORMAT,
    version: COMPLETE_BACKUP_VERSION,
    exportedAt: value.exportedAt,
    appData: value.appData as RengeAppData,
    localStorage: storageEntries,
    ...(isObjectRecord(value.desktopProjectPositions)
      ? { desktopProjectPositions: value.desktopProjectPositions }
      : {}),
  };
}

function getCompleteBackupFileTimestamp(date: Date) {
  const pad = (value: number) => String(value).padStart(2, "0");
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}-${pad(date.getHours())}${pad(date.getMinutes())}${pad(date.getSeconds())}`;
}

function getStoredPcConnection(): PcConnectionData {
  return {
    baseUrl: localStorage.getItem(PC_SERVER_URL_STORAGE_KEY) ?? "",
    workspacePath: localStorage.getItem(PC_WORKSPACE_PATH_STORAGE_KEY) ?? "",
    workspaceName: localStorage.getItem(PC_WORKSPACE_NAME_STORAGE_KEY) ?? "",
  };
}

function normalizePcWorkspaceHandle(connection: PcConnectionData | undefined | null) {
  const baseUrl = typeof connection?.baseUrl === "string" ? connection.baseUrl.trim() : "";
  const path =
    typeof connection?.workspacePath === "string" ? connection.workspacePath.trim() : "";
  if (!baseUrl || !path) return null;
  const name =
    typeof connection?.workspaceName === "string" && connection.workspaceName.trim()
      ? connection.workspaceName.trim()
      : path.replace(/[\\/]+$/g, "").split(/[\\/]/).filter(Boolean).at(-1) || "з”өи„‘е·ҘдҪңеҢә";
  return {
    kind: "pc" as const,
    name,
    baseUrl,
    path,
  };
}

function syncPcConnectionToLocalStorage(baseUrl: string, workspace: PcWorkspaceHandle | null) {
  localStorage.setItem(PC_SERVER_URL_STORAGE_KEY, baseUrl);
  if (workspace) {
    localStorage.setItem(PC_SERVER_URL_STORAGE_KEY, workspace.baseUrl);
    localStorage.setItem(PC_WORKSPACE_PATH_STORAGE_KEY, workspace.path);
    localStorage.setItem(PC_WORKSPACE_NAME_STORAGE_KEY, workspace.name);
    return;
  }
  localStorage.removeItem(PC_WORKSPACE_PATH_STORAGE_KEY);
  localStorage.removeItem(PC_WORKSPACE_NAME_STORAGE_KEY);
}

function inferChatSessionTitle(messages: ChatMessage[]) {
  const firstUserMessage = messages.find(
    (message) => message.role === "user" && !isHeartbeatCheckMessage(message),
  );
  const title = firstUserMessage?.content.trim().replace(/\s+/g, " ");
  if (title) return title.slice(0, 32);
  const firstAttachmentName = firstUserMessage?.attachments?.[0]?.name;
  return firstAttachmentName ? `ж–Үд»¶пјҡ${firstAttachmentName}`.slice(0, 32) : "ж–°дјҡиҜқ";
}

function isHeartbeatCheckMessage(message: ChatMessage) {
  return message.source === "heartbeat" || message.content.trim().startsWith("гҖҗеҝғи·іжЈҖжҹҘгҖ‘");
}

function isHeartbeatToolProgressMessage(message: ChatMessage) {
  const content = message.content.trim();
  if (message.role !== "assistant") return false;
  return (
    content === "жӣҙж–°еҪ“еүҚдјҡиҜқеҝғи·іи®ҫзҪ®гҖӮ" ||
    content.startsWith("еҝғи·іе·Іжӣҙж–°пјҡ") ||
    content.startsWith("еҝғи·іе°ҶеңЁжң¬иҪ®еҝғи·іе®ҢжҲҗеҗҺжӣҙж–°пјҡ") ||
    content.includes("chat_update_heartbeat")
  );
}

function isHeartbeatUiReminderMessage(message: ChatMessage) {
  return isHeartbeatCheckMessage(message) || isHeartbeatToolProgressMessage(message);
}

function isToolProgressStartLine(line: string) {
  const trimmedLine = line.trim();
  if (!trimmedLine) return false;
  if (trimmedLine.startsWith("жү§иЎҢ MCP е·Ҙе…·пјҡ")) return true;
  if (trimmedLine.startsWith("MCP е·Ҙе…·жү§иЎҢе®ҢжҲҗ")) return true;
  if (trimmedLine.startsWith("MCP е·Ҙе…·еӨұиҙҘпјҡ")) return true;
  if (trimmedLine.startsWith("ж“ҚдҪңеӨұиҙҘпјҡ")) return true;
  if (toolActionTitleMap.some(([prefix]) => trimmedLine.startsWith(prefix))) return true;
  return Boolean(parseToolProgressContent(trimmedLine));
}

function isLikelyPlainNarrationLine(line: string) {
  const trimmedLine = line.trim();
  if (!trimmedLine) return false;
  if (/^[{[\]},\]"]/.test(trimmedLine)) return false;
  if (/^(еҸӮж•°|иҫ“еҮә|й”ҷиҜҜиҫ“еҮә|йў„и§Ҳ)пјҡ/.test(trimmedLine)) return false;
  if (/^[A-Za-z0-9_$.-]+:/.test(trimmedLine)) return false;
  if (/^[-*]\s/.test(trimmedLine)) return false;
  return /[\u4e00-\u9fff]/.test(trimmedLine);
}

function splitAssistantToolProgressSegments(content: string) {
  const rawLines = content.replace(/\r\n/g, "\n").split("\n");
  const segments: string[] = [];
  let currentLines: string[] = [];
  let currentKind: "text" | "tool" | null = null;

  const flush = () => {
    const segment = currentLines.join("\n").trim();
    if (segment) segments.push(segment);
    currentLines = [];
    currentKind = null;
  };

  for (const rawLine of rawLines) {
    const trimmedLine = rawLine.trim();
    const isToolStart = isToolProgressStartLine(trimmedLine);

    if (isToolStart) {
      flush();
      currentKind = "tool";
      currentLines.push(rawLine);
      continue;
    }

    if (
      currentKind === "tool" &&
      trimmedLine &&
      isLikelyPlainNarrationLine(trimmedLine) &&
      currentLines.some((line) => line.trim().startsWith("MCP е·Ҙе…·жү§иЎҢе®ҢжҲҗ"))
    ) {
      flush();
      currentKind = "text";
      currentLines.push(rawLine);
      continue;
    }

    if (currentKind === null) {
      currentKind = "text";
    }
    currentLines.push(rawLine);
  }

  flush();

  if (segments.length <= 1) return [content];
  if (!segments.some((segment) => parseToolProgressContent(segment))) return [content];
  return segments;
}

function getChatMessageSegments(message: ChatMessage, splitShortChatLines = true) {
  const content = message.content.trim();
  if (!content) return [""];
  if (message.role !== "assistant") return [content];
  if (parseToolProgressContent(content)) return [content];
  if (content.includes("```")) return [content];
  if (containsChatAudioMarkup(content)) return [content];

  const toolProgressSegments = splitAssistantToolProgressSegments(content);
  if (toolProgressSegments.length > 1) return toolProgressSegments;
  if (!splitShortChatLines) return [content];

  const lines = content
    .replace(/\r\n/g, "\n")
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean);

  if (lines.length <= 1 || lines.length > 4) return [content];

  const hasMarkdownStructure = lines.some((line) =>
    /^(#{1,6}\s|[-*+]\s|\d+\.\s|>\s|\|)/.test(line),
  );
  if (hasMarkdownStructure) return [content];

  const allShortChatLines = lines.every((line) => line.length <= 80);
  return allShortChatLines ? lines : [content];
}

function getRenderedChatSegments(messages: ChatMessage[], multiBubbleEnabled: boolean) {
  let previousTimestamp: number | null = null;

  return messages.flatMap((message) => {
    const timestamp = new Date(message.createdAt).getTime();
    const messageSegments =
      message.renderAsPlainText
        ? [message.content]
        : message.role === "assistant"
        ? getChatMessageSegments(message, multiBubbleEnabled)
        : multiBubbleEnabled
          ? getChatMessageSegments(message)
          : [message.content];

    return messageSegments.map((segment, segmentIndex) => {
      const showTime =
        previousTimestamp === null ||
        Math.abs(timestamp - previousTimestamp) >= CHAT_TIME_GROUP_MS;
      previousTimestamp = timestamp;

      return {
        id: `${message.id}-${segmentIndex}`,
        message,
        segment,
        segmentIndex,
        showTime,
      };
    });
  });
}

type RenderedChatSegment = ReturnType<typeof getRenderedChatSegments>[number];

type RenderedChatItem =
  | ({ kind: "segment" } & RenderedChatSegment)
  | {
      kind: "toolGroup";
      id: string;
      message: ChatMessage;
      segments: RenderedChatSegment[];
      blocks: ChatToolProgressBlock[];
      showTime: boolean;
      startedAt: string;
      endedAt: string;
    };

type ChatContentPart =
  | { type: "text"; content: string }
  | { type: "code"; content: string; language: string; executable: boolean }
  | ChatAudioEmbed
  | ChatLiveStreamEmbed;

type HtmlPreviewContext = {
  currentMessageIndex: number;
  messages: Array<{
    role: ChatRole;
    content: string;
    variables: Record<string, unknown>;
    extra: Record<string, unknown>;
  }>;
  chatVariables: Record<string, unknown>;
  characterVariables: Record<string, unknown>;
  globalVariables: Record<string, unknown>;
  presetVariables: Record<string, unknown>;
  extensionVariables: Record<string, Record<string, unknown>>;
  userName: string;
  characterName: string;
  chatId: string;
  chatInput: string;
  personalization: Pick<
    ChatPersonalizationSettings,
    "quoteStyleEnabled" | "quoteStyleColor"
  >;
};

type ChatToolProgressLink = {
  label: string;
  href?: string;
};

type ChatToolProgressBlock = {
  variant: "action" | "success" | "error";
  title: string;
  badge: string;
  links: ChatToolProgressLink[];
  details: string[];
};

