const HTML_PREVIEW_HEAVY_MOUNT_GAP = 900;
const HTML_PREVIEW_HEAVY_AUTO_LOAD_DELAY = 5000;

type HeavyHtmlPreviewMountTask = {
  cancelled: boolean;
  mount: () => void;
};

const heavyHtmlPreviewMountQueue: HeavyHtmlPreviewMountTask[] = [];
let heavyHtmlPreviewMountActive = false;
const HTML_PREVIEW_HEAVY_ACTIVE_LIMIT = 3;
const activeHeavyHtmlPreviewIds: string[] = [];
const heavyHtmlPreviewListeners = new Map<string, (active: boolean) => void>();

function activateHeavyHtmlPreview(previewId: string) {
  const existingIndex = activeHeavyHtmlPreviewIds.indexOf(previewId);
  if (existingIndex >= 0) activeHeavyHtmlPreviewIds.splice(existingIndex, 1);
  activeHeavyHtmlPreviewIds.push(previewId);
  while (activeHeavyHtmlPreviewIds.length > HTML_PREVIEW_HEAVY_ACTIVE_LIMIT) {
    activeHeavyHtmlPreviewIds.shift();
  }
  heavyHtmlPreviewListeners.forEach((listener, candidateId) => {
    listener(activeHeavyHtmlPreviewIds.includes(candidateId));
  });
}

function subscribeHeavyHtmlPreview(
  previewId: string,
  listener: (active: boolean) => void,
) {
  heavyHtmlPreviewListeners.set(previewId, listener);
  listener(activeHeavyHtmlPreviewIds.includes(previewId));
  return () => {
    heavyHtmlPreviewListeners.delete(previewId);
    const index = activeHeavyHtmlPreviewIds.indexOf(previewId);
    if (index >= 0) activeHeavyHtmlPreviewIds.splice(index, 1);
  };
}

function drainHeavyHtmlPreviewMountQueue() {
  if (heavyHtmlPreviewMountActive) return;
  const task = heavyHtmlPreviewMountQueue.shift();
  if (!task) return;
  if (task.cancelled) {
    window.setTimeout(drainHeavyHtmlPreviewMountQueue, 0);
    return;
  }

  heavyHtmlPreviewMountActive = true;
  const mount = () => {
    if (!task.cancelled) task.mount();
    window.setTimeout(() => {
      heavyHtmlPreviewMountActive = false;
      drainHeavyHtmlPreviewMountQueue();
    }, HTML_PREVIEW_HEAVY_MOUNT_GAP);
  };

  if (typeof window.requestIdleCallback === "function") {
    window.requestIdleCallback(mount, { timeout: 1200 });
  } else {
    window.setTimeout(mount, 0);
  }
}

function enqueueHeavyHtmlPreviewMount(mount: () => void) {
  const task: HeavyHtmlPreviewMountTask = { cancelled: false, mount };
  heavyHtmlPreviewMountQueue.push(task);
  drainHeavyHtmlPreviewMountQueue();
  return () => {
    task.cancelled = true;
  };
}

type ParsedTavernSlashCommand =
  | { type: "set-input"; text: string; append: boolean; submit: boolean }
  | { type: "send-as"; text: string; name: string }
  | {
      type: "echo";
      text: string;
      title: string;
      severity: "info" | "success" | "warning" | "error";
      duration: number;
    }
  | { type: "trigger" };

function parseTavernSlashCommand(command: string): ParsedTavernSlashCommand | null {
  const normalized = command.trim();
  if (!normalized) return null;
  const parts = normalized.split(/\s*\|\s*(?=\/)/);
  const primary = parts.shift()?.trim() ?? "";
  const hasTrigger = parts.some((part) => /^\/(?:trigger|gen)\b/i.test(part.trim()));

  const echoMatch = /^\/echo\b(?:\s+([\s\S]*))?$/i.exec(primary);
  if (echoMatch) {
    let remainder = (echoMatch[1] ?? "").trim();
    let severity: "info" | "success" | "warning" | "error" = "info";
    let title = "";
    let duration = 0;
    while (remainder) {
      const optionMatch =
        /^(severity|title|duration|timeout)=(?:"([^"]*)"|'([^']*)'|(\S+))(?:\s+|$)/i.exec(
          remainder,
        );
      if (!optionMatch) break;
      const optionName = optionMatch[1].toLowerCase();
      const optionValue = optionMatch[2] ?? optionMatch[3] ?? optionMatch[4] ?? "";
      if (optionName === "severity") {
        const normalizedSeverity = optionValue.toLowerCase();
        if (normalizedSeverity === "success" || normalizedSeverity === "positive") {
          severity = "success";
        } else if (normalizedSeverity === "warning" || normalizedSeverity === "warn") {
          severity = "warning";
        } else if (
          normalizedSeverity === "error" ||
          normalizedSeverity === "danger" ||
          normalizedSeverity === "negative"
        ) {
          severity = "error";
        } else {
          severity = "info";
        }
      } else if (optionName === "title") {
        title = optionValue;
      } else {
        const numericDuration = Number(optionValue);
        if (Number.isFinite(numericDuration) && numericDuration > 0) {
          duration = Math.min(Math.round(numericDuration), 60_000);
        }
      }
      remainder = remainder.slice(optionMatch[0].length).trimStart();
    }
    return { type: "echo", text: remainder, title, severity, duration };
  }

  const sendAsMatch = /^\/sendas\b\s*([\s\S]*)$/i.exec(primary);
  if (sendAsMatch) {
    let remainder = sendAsMatch[1].trim();
    let name = "";
    const nameMatch = /^name=(?:"([^"]*)"|'([^']*)'|(\S+))\s*/i.exec(remainder);
    if (nameMatch) {
      name = nameMatch[1] ?? nameMatch[2] ?? nameMatch[3] ?? "";
      remainder = remainder.slice(nameMatch[0].length);
    }
    return remainder ? { type: "send-as", text: remainder, name } : null;
  }

  const setInputMatch = /^\/setinput(?:\s+([\s\S]*))?$/i.exec(primary);
  if (setInputMatch) {
    return {
      type: "set-input",
      text: setInputMatch[1] ?? "",
      append: false,
      submit: hasTrigger,
    };
  }

  const appendInputMatch = /^\/appendinput(?:\s+([\s\S]*))?$/i.exec(primary);
  if (appendInputMatch) {
    return {
      type: "set-input",
      text: appendInputMatch[1] ?? "",
      append: true,
      submit: hasTrigger,
    };
  }

  const sendMatch = /^\/send(?:\s+([\s\S]*))?$/i.exec(primary);
  if (sendMatch) {
    return {
      type: "set-input",
      text: sendMatch[1] ?? "",
      append: false,
      submit: true,
    };
  }

  if (/^\/(?:trigger|gen)\b/i.test(primary)) return { type: "trigger" };
  return null;
}
